// src/services/api.js
const API_URL = 'http://localhost:5000/api';

// Check backend connection
export const checkHealth = async () => {
  const response = await fetch(`${API_URL}/health`);
  return response.json();
};

// Get all courses
export const getCourses = async () => {
  const response = await fetch(`${API_URL}/courses`);
  const data = await response.json();
  return data.courses; // Array of courses
};

// Add sample courses (for development)
export const addSampleCourses = async () => {
  const response = await fetch(`${API_URL}/add-sample-courses`, {
    method: 'POST',
  });
  return response.json();
};

// Get all notes
export const getNotes = async () => {
  const response = await fetch(`${API_URL}/notes`);
  const data = await response.json();
  return data.notes;
};

// Add sample notes
export const addSampleNotes = async () => {
  const response = await fetch(`${API_URL}/add-sample-notes`, {
    method: 'POST',
  });
  return response.json();
};

// Get database info
export const getDBInfo = async () => {
  const response = await fetch(`${API_URL}/db-info`);
  return response.json();
};

export default {
  checkHealth,
  getCourses,
  addSampleCourses,
  getNotes,
  addSampleNotes,
  getDBInfo
};
